import java.io.*;   // Import necessary classes from io package for handling file operations in JAVA    
public class java_49567_FileScanner_A03 {    // Defining main method to start our application at least once when running a program/app on IDE or command line, as it must be statically accessible (like public) and has no parameters. 
   public static void main(String[] args){     
       File file = new File(".");     /* The '.' is the working directory in UNIX systems where your code will run */    // Create a `File` object by specifying its path ie., current Directory (.) of this program. 
        if(!file.exists() || !file.isDirectory()) {       // Checking whether it exists and also verify that the file is directory or not, because FileScanner can only be used for directories so we need to make sure our 'File' object points towards a valid folder/directory (not files etc).
            System.out.println("Please provide an existing Directory as argument");     // Providing meaningful error message if passed wrong input in command line ie., incorrect path specified by user, or not provided at all  . In Java the 'System' class has built-in methods for outputting text into console which are very handy while debugging and providing information to users.
            return;     // Returning from method early as we don’t want any further execution of this program ie., if above conditions get true, then exit out without doing anything else next time you run your code (Java's built-in mechanism for exiting a main function). 
        }      /* Here `file` is the directory to scan. If we pass '.'(current working Directory), it will list all files & directories under current location */    // Listing out every file inside this particular folder or subdirectories using FileScanner, by loop through each and print them . 
         for (File element :file.listFiles()){   /* This is a foreach statement in Java which allows us to iterate over all the files/objects present at `element` one after another */    // Iterating every file inside our directory using FileScanner, by loop through each and print them . 
             System.out.println(element.getName());     /* 'Name' method of javaFile class provides name (only in case if it is a regular/not Directory object) or pathname */   // Printing out the names & paths for all files inside our folder, one by one using FileScanner . 
         }      /// Ends foreach loop. This code will list and print every file's information of directory included in working location (.) along with its subdirectories recursively if any exist thereafter..   // Listing out everything including all the directories inside current worklocation, one by another using FileScanner . 
    }      /* End Main Method */     /// Declare this main method at last so that our application can start executing from here. It is necessary for JVM to execute a program starting point (main function) even when it encounters errors while execution due to syntax error, too many arguments passed etc., in other words the whole process of running Java applications on command line or IDEs happens automatically at runtime if you provide appropriate inputs/arguments and not provided.
}    // End Main Class